parameters.old_string:
/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications.
 *
 * TODO(multi-channel): This model was designed assuming email-only delivery.
 * Now that SMS is a supported channel, the preferences model needs to be
 * updated to support per-channel settings. Specifically:
 *
 * 1. Replace `emailEnabled` / `emailFrequency` with a channel-aware structure,
 *    e.g. a `channels` map: { email: { enabled, frequency }, sms: { enabled } }
 * 2. The `enabledCategories` list currently applies globally — consider making
 *    it per-channel so users can get order updates via SMS but digests via email.
 * 3. `CreateUserPreferencesInput` and `UpdateUserPreferencesInput` need matching
 *    updates to accept per-channel settings.
 * 4. `DEFAULT_PREFERENCES` should define sensible defaults for each channel
 *    (e.g. SMS off by default, email on by default).
 * 5. `PreferencesService.shouldSendNotification()` needs a `channel` parameter
 *    so it can gate notifications per-channel, not just globally.
 * 6. The `PreferencesService.getEmailFrequency()` method is email-specific and
 *    will need a channel-agnostic replacement or SMS-specific counterpart.
 *
 * See also: src/services/preferences.service.ts, src/services/notification.service.ts
 */

import type { NotificationType } from './notification.js';

/**
 * How frequently email notifications are delivered.
 * - immediate: sent as soon as the event occurs
 * - daily_digest: batched and sent once per day
 * - weekly_digest: batched and sent once per week
 */
export type EmailFrequency = 'immediate' | 'daily_digest' | 'weekly_digest';

/**
 * Persisted user notification preferences.
 */
export interface UserPreferences {
  id: string;
  userId: string;
  emailEnabled: boolean;
  emailFrequency: EmailFrequency;
  enabledCategories: NotificationType[];
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for creating user preferences.
 */
export interface CreateUserPreferencesInput {
  userId: string;
  emailEnabled?: boolean;
  emailFrequency?: EmailFrequency;
  enabledCategories?: NotificationType[];
}

/**
 * Input for updating user preferences.
 */
export interface UpdateUserPreferencesInput {
  emailEnabled?: boolean;
  emailFrequency?: EmailFrequency;
  enabledCategories?: NotificationType[];
}

/**
 * All available notification categories.
 */
export const ALL_NOTIFICATION_CATEGORIES: NotificationType[] = [
  'order_confirmation',
  'order_status_update',
  'welcome',
  'account_updated',
];

/**
 * Default preferences for new users — all emails enabled, immediate delivery.
 */
export const DEFAULT_PREFERENCES: Omit<UserPreferences, 'id' | 'userId' | 'createdAt' | 'updatedAt'> = {
  emailEnabled: true,
  emailFrequency: 'immediate',
  enabledCategories: [...ALL_NOTIFICATION_CATEGORIES],
};

parameters.new_string:
/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications across multiple channels.
 *
 * DECISION CHANGE (Session 9): This model originally assumed email-only delivery
 * (Session 3). With SMS support added (Session 8) and webhook already present,
 * the preferences model now supports per-channel settings. Each channel has its
 * own enabled flag and category list, allowing users to receive e.g. order
 * updates via SMS but digests only via email.
 *
 * Backward compatibility: The legacy fields `emailEnabled`, `emailFrequency`,
 * and `enabledCategories` are preserved and kept in sync with `channels.email`.
 * Code that only reads the legacy fields will continue to work correctly.
 */

import type { NotificationType, NotificationChannel } from './notification.js';

/**
 * How frequently email notifications are delivered.
 * - immediate: sent as soon as the event occurs
 * - daily_digest: batched and sent once per day
 * - weekly_digest: batched and sent once per week
 */
export type EmailFrequency = 'immediate' | 'daily_digest' | 'weekly_digest';

/**
 * Per-channel notification preferences.
 */
export interface ChannelPreferences {
  enabled: boolean;
  categories: NotificationType[];
}

/**
 * Email-specific channel preferences (adds frequency control).
 */
export interface EmailChannelPreferences extends ChannelPreferences {
  frequency: EmailFrequency;
}

/**
 * Map of per-channel notification preferences.
 */
export interface ChannelPreferencesMap {
  email: EmailChannelPreferences;
  sms: ChannelPreferences;
  webhook: ChannelPreferences;
}

/**
 * Channels that support per-channel preferences.
 */
export type PreferenceChannel = keyof ChannelPreferencesMap;

/**
 * Persisted user notification preferences.
 *
 * The `channels` map holds per-channel settings. The top-level `emailEnabled`,
 * `emailFrequency`, and `enabledCategories` fields are backward-compatible
 * aliases for `channels.email` and are kept in sync by the PreferencesService.
 */
export interface UserPreferences {
  id: string;
  userId: string;
  /** @deprecated Use channels.email.enabled */
  emailEnabled: boolean;
  /** @deprecated Use channels.email.frequency */
  emailFrequency: EmailFrequency;
  /** @deprecated Use channels.email.categories */
  enabledCategories: NotificationType[];
  channels: ChannelPreferencesMap;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Per-channel input for creating/updating preferences.
 */
export interface ChannelPreferencesInput {
  enabled?: boolean;
  categories?: NotificationType[];
}

export interface EmailChannelPreferencesInput extends ChannelPreferencesInput {
  frequency?: EmailFrequency;
}

/**
 * Input for creating user preferences.
 * Supports both legacy email-only fields and new per-channel settings.
 */
export interface CreateUserPreferencesInput {
  userId: string;
  /** @deprecated Use channels.email.enabled */
  emailEnabled?: boolean;
  /** @deprecated Use channels.email.frequency */
  emailFrequency?: EmailFrequency;
  /** @deprecated Use channels.email.categories */
  enabledCategories?: NotificationType[];
  channels?: {
    email?: EmailChannelPreferencesInput;
    sms?: ChannelPreferencesInput;
    webhook?: ChannelPreferencesInput;
  };
}

/**
 * Input for updating user preferences.
 * Supports both legacy email-only fields and new per-channel settings.
 */
export interface UpdateUserPreferencesInput {
  /** @deprecated Use channels.email.enabled */
  emailEnabled?: boolean;
  /** @deprecated Use channels.email.frequency */
  emailFrequency?: EmailFrequency;
  /** @deprecated Use channels.email.categories */
  enabledCategories?: NotificationType[];
  channels?: {
    email?: EmailChannelPreferencesInput;
    sms?: ChannelPreferencesInput;
    webhook?: ChannelPreferencesInput;
  };
}

/**
 * All available notification categories.
 */
export const ALL_NOTIFICATION_CATEGORIES: NotificationType[] = [
  'order_confirmation',
  'order_status_update',
  'welcome',
  'account_updated',
];

/**
 * Default channel preferences: email on (immediate), SMS off, webhook off.
 */
export const DEFAULT_CHANNEL_PREFERENCES: ChannelPreferencesMap = {
  email: {
    enabled: true,
    frequency: 'immediate',
    categories: [...ALL_NOTIFICATION_CATEGORIES],
  },
  sms: {
    enabled: false,
    categories: [...ALL_NOTIFICATION_CATEGORIES],
  },
  webhook: {
    enabled: false,
    categories: [...ALL_NOTIFICATION_CATEGORIES],
  },
};

/**
 * Default preferences for new users.
 * Legacy fields mirror channels.email for backward compatibility.
 */
export const DEFAULT_PREFERENCES: Omit<UserPreferences, 'id' | 'userId' | 'createdAt' | 'updatedAt'> = {
  emailEnabled: true,
  emailFrequency: 'immediate',
  enabledCategories: [...ALL_NOTIFICATION_CATEGORIES],
  channels: {
    email: { ...DEFAULT_CHANNEL_PREFERENCES.email, categories: [...DEFAULT_CHANNEL_PREFERENCES.email.categories] },
    sms: { ...DEFAULT_CHANNEL_PREFERENCES.sms, categories: [...DEFAULT_CHANNEL_PREFERENCES.sms.categories] },
    webhook: { ...DEFAULT_CHANNEL_PREFERENCES.webhook, categories: [...DEFAULT_CHANNEL_PREFERENCES.webhook.categories] },
  },
};

