import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserPreferences, ChannelPreferencesMap } from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';
import type { EmailFrequency } from '../models/user-preferences.js';
import { DEFAULT_CHANNEL_PREFERENCES } from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class UserPreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    const emailEnabled = record['emailEnabled'] as boolean;
    const emailFrequency = record['emailFrequency'] as EmailFrequency;
    const enabledCategories = JSON.parse(record['enabledCategories'] as string) as NotificationType[];

    // Deserialize channels if present, otherwise reconstruct from legacy fields
    let channels: ChannelPreferencesMap;
    if (record['channels']) {
      channels = JSON.parse(record['channels'] as string) as ChannelPreferencesMap;
    } else {
      channels = {
        email: { enabled: emailEnabled, frequency: emailFrequency, categories: [...enabledCategories] },
        sms: { ...DEFAULT_CHANNEL_PREFERENCES.sms, categories: [...DEFAULT_CHANNEL_PREFERENCES.sms.categories] },
        webhook: { ...DEFAULT_CHANNEL_PREFERENCES.webhook, categories: [...DEFAULT_CHANNEL_PREFERENCES.webhook.categories] },
      };
    }

    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      emailEnabled,
      emailFrequency,
      enabledCategories,
      channels,
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      emailEnabled: entity.emailEnabled,
      emailFrequency: entity.emailFrequency,
      enabledCategories: JSON.stringify(entity.enabledCategories),
      channels: JSON.stringify(entity.channels),
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

parameters.content:
/**
 * User notification preferences service.
 *
 * Manages user notification preferences — what notifications they receive
 * and how they are delivered across multiple channels (email, SMS, webhook).
 *
 * DECISION CHANGE (Session 9): This service originally assumed email-only
 * delivery. With SMS (Session 8) and webhook channels now available,
 * `shouldSendNotification` accepts an optional `channel` parameter and
 * preferences are managed per-channel. Legacy callers that omit the channel
 * parameter default to 'email' for backward compatibility.
 *
 * Depends on:
 * - UserPreferencesRepository for data access
 * - EventBus for reacting to user creation (auto-create default preferences)
 */

import type { EventBus } from '../events/event-bus.js';
import type { UserCreatedEvent } from '../events/event-types.js';
import type { UserPreferencesRepository } from '../repositories/user-preferences.repository.js';
import type {
  UserPreferences,
  CreateUserPreferencesInput,
  UpdateUserPreferencesInput,
  PreferenceChannel,
} from '../models/user-preferences.js';
import type { NotificationType, NotificationChannel } from '../models/notification.js';
import {
  DEFAULT_PREFERENCES,
  DEFAULT_CHANNEL_PREFERENCES,
  ALL_NOTIFICATION_CATEGORIES,
} from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';
import { validatePreferencesNotExist, validatePreferencesExist } from '../validators/preferences.validator.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

/**
 * Map a NotificationChannel to a PreferenceChannel.
 * Channels without explicit preference support (e.g. in_app) are not mapped.
 */
function toPreferenceChannel(channel: NotificationChannel): PreferenceChannel | undefined {
  if (channel === 'email' || channel === 'sms' || channel === 'webhook') {
    return channel;
  }
  return undefined;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(
    private repository: UserPreferencesRepository,
    private eventBus: EventBus,
  ) {
    this.registerEventHandlers();
  }

  /**
   * Subscribe to user creation events to auto-create default preferences.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<UserCreatedEvent>('user:created', (event) => {
      this.createDefaultPreferences(event.user.id);
    });
  }

  /**
   * Create default preferences for a new user.
   */
  private createDefaultPreferences(userId: string): void {
    const existing = this.repository.findByUserId(userId);
    if (existing) {
      this.logger.info(`Preferences already exist for user ${userId}`);
      return;
    }

    this.logger.info(`Creating default preferences for user ${userId}`);
    const now = new Date();
    const preferences: UserPreferences = {
      id: generatePreferencesId(),
      userId,
      ...DEFAULT_PREFERENCES,
      enabledCategories: [...DEFAULT_PREFERENCES.enabledCategories],
      channels: {
        email: { ...DEFAULT_PREFERENCES.channels.email, categories: [...DEFAULT_PREFERENCES.channels.email.categories] },
        sms: { ...DEFAULT_PREFERENCES.channels.sms, categories: [...DEFAULT_PREFERENCES.channels.sms.categories] },
        webhook: { ...DEFAULT_PREFERENCES.channels.webhook, categories: [...DEFAULT_PREFERENCES.channels.webhook.categories] },
      },
      createdAt: now,
      updatedAt: now,
    };

    this.repository.save(preferences);
  }

  /**
   * Get preferences for a user. Returns undefined if not found.
   */
  getPreferences(userId: string): UserPreferences | undefined {
    return this.repository.findByUserId(userId);
  }

  /**
   * Create preferences for a user with custom settings.
   * Throws if the user already has preferences.
   *
   * Supports both legacy email-only fields and new per-channel settings.
   * If both are provided, per-channel settings take precedence for the
   * respective channel.
   */
  createPreferences(input: CreateUserPreferencesInput): UserPreferences {
    const existing = this.repository.findByUserId(input.userId);
    validatePreferencesNotExist(existing, input.userId);

    const emailEnabled = input.channels?.email?.enabled ?? input.emailEnabled ?? DEFAULT_PREFERENCES.emailEnabled;
    const emailFrequency = input.channels?.email?.frequency ?? input.emailFrequency ?? DEFAULT_PREFERENCES.emailFrequency;
    const emailCategories = input.channels?.email?.categories ?? input.enabledCategories ?? [...DEFAULT_PREFERENCES.channels.email.categories];

    const now = new Date();
    const preferences: UserPreferences = {
      id: generatePreferencesId(),
      userId: input.userId,
      emailEnabled,
      emailFrequency,
      enabledCategories: [...emailCategories],
      channels: {
        email: {
          enabled: emailEnabled,
          frequency: emailFrequency,
          categories: [...emailCategories],
        },
        sms: {
          enabled: input.channels?.sms?.enabled ?? DEFAULT_CHANNEL_PREFERENCES.sms.enabled,
          categories: input.channels?.sms?.categories
            ? [...input.channels.sms.categories]
            : [...DEFAULT_CHANNEL_PREFERENCES.sms.categories],
        },
        webhook: {
          enabled: input.channels?.webhook?.enabled ?? DEFAULT_CHANNEL_PREFERENCES.webhook.enabled,
          categories: input.channels?.webhook?.categories
            ? [...input.channels.webhook.categories]
            : [...DEFAULT_CHANNEL_PREFERENCES.webhook.categories],
        },
      },
      createdAt: now,
      updatedAt: now,
    };

    this.repository.save(preferences);
    this.logger.info(`Created preferences for user ${input.userId}`);
    return preferences;
  }

  /**
   * Update preferences for a user.
   * Throws if the user has no preferences.
   *
   * Supports both legacy email-only fields and new per-channel settings.
   */
  updatePreferences(userId: string, input: UpdateUserPreferencesInput): UserPreferences {
    const existing = this.repository.findByUserId(userId);
    validatePreferencesExist(existing, userId);

    const updates: Partial<UserPreferences> = { updatedAt: new Date() };

    // Apply legacy email fields
    if (input.emailEnabled !== undefined) {
      updates.emailEnabled = input.emailEnabled;
    }
    if (input.emailFrequency !== undefined) {
      updates.emailFrequency = input.emailFrequency;
    }
    if (input.enabledCategories !== undefined) {
      updates.enabledCategories = [...input.enabledCategories];
    }

    // Build updated channels map starting from existing
    const updatedChannels = {
      email: { ...existing.channels.email },
      sms: { ...existing.channels.sms },
      webhook: { ...existing.channels.webhook },
    };

    // Sync legacy fields into email channel
    if (input.emailEnabled !== undefined) {
      updatedChannels.email.enabled = input.emailEnabled;
    }
    if (input.emailFrequency !== undefined) {
      updatedChannels.email.frequency = input.emailFrequency;
    }
    if (input.enabledCategories !== undefined) {
      updatedChannels.email.categories = [...input.enabledCategories];
    }

    // Apply per-channel overrides (take precedence over legacy fields)
    if (input.channels?.email) {
      if (input.channels.email.enabled !== undefined) {
        updatedChannels.email.enabled = input.channels.email.enabled;
        updates.emailEnabled = input.channels.email.enabled;
      }
      if (input.channels.email.frequency !== undefined) {
        updatedChannels.email.frequency = input.channels.email.frequency;
        updates.emailFrequency = input.channels.email.frequency;
      }
      if (input.channels.email.categories !== undefined) {
        updatedChannels.email.categories = [...input.channels.email.categories];
        updates.enabledCategories = [...input.channels.email.categories];
      }
    }
    if (input.channels?.sms) {
      if (input.channels.sms.enabled !== undefined) {
        updatedChannels.sms.enabled = input.channels.sms.enabled;
      }
      if (input.channels.sms.categories !== undefined) {
        updatedChannels.sms.categories = [...input.channels.sms.categories];
      }
    }
    if (input.channels?.webhook) {
      if (input.channels.webhook.enabled !== undefined) {
        updatedChannels.webhook.enabled = input.channels.webhook.enabled;
      }
      if (input.channels.webhook.categories !== undefined) {
        updatedChannels.webhook.categories = [...input.channels.webhook.categories];
      }
    }

    updates.channels = updatedChannels;

    const updated = this.repository.update(existing.id, updates);
    this.logger.info(`Updated preferences for user ${userId}`);
    return updated;
  }

  /**
   * Check whether a notification should be sent to a user on a given channel.
   * Returns true if the notification should be sent.
   *
   * If no preferences exist for the user, defaults to allowing the notification
   * (opt-out model: notifications are sent unless explicitly disabled).
   *
   * @param channel - The delivery channel to check. Defaults to 'email' for
   *   backward compatibility with callers that pre-date multi-channel support.
   */
  shouldSendNotification(
    userId: string,
    notificationType: NotificationType,
    channel: NotificationChannel = 'email',
  ): boolean {
    const preferences = this.repository.findByUserId(userId);

    if (!preferences) {
      return true;
    }

    const prefChannel = toPreferenceChannel(channel);
    if (!prefChannel) {
      // Channels without explicit preference support (e.g. in_app) are allowed
      return true;
    }

    const channelPrefs = preferences.channels[prefChannel];
    if (!channelPrefs.enabled) {
      return false;
    }

    return channelPrefs.categories.includes(notificationType);
  }

  /**
   * Get the email frequency setting for a user.
   * Returns 'immediate' if no preferences exist.
   */
  getEmailFrequency(userId: string): UserPreferences['emailFrequency'] {
    const preferences = this.repository.findByUserId(userId);
    return preferences?.channels.email.frequency ?? 'immediate';
  }

  /**
   * Get the enabled channels for a specific notification type.
   * Returns the list of channels that should receive this notification.
   */
  getEnabledChannels(userId: string, notificationType: NotificationType): PreferenceChannel[] {
    const preferences = this.repository.findByUserId(userId);

    if (!preferences) {
      // Default: only email is enabled for new/unknown users
      return ['email'];
    }

    const enabled: PreferenceChannel[] = [];
    for (const [channel, prefs] of Object.entries(preferences.channels)) {
      if (prefs.enabled && prefs.categories.includes(notificationType)) {
        enabled.push(channel as PreferenceChannel);
      }
    }
    return enabled;
  }
}

/**
 * Notification service — central hub for all notification delivery.
 *
 * Architecture: Event-driven with adapter-based delivery.
 *
 * 1. Domain services (OrderService, UserService) emit events via EventBus.
 * 2. NotificationService subscribes to relevant events and constructs
 *    NotificationPayload objects.
 * 3. Payloads are dispatched to the appropriate NotificationAdapter
 *    based on the notification's channel.
 * 4. When a PreferencesService is configured, notifications are sent to all
 *    channels the user has enabled for the notification type.
 *
 * CONSTRAINTS:
 * - All notifications MUST flow through EventBus — no direct calls.
 * - All delivery channels MUST implement the NotificationAdapter interface.
 * - Adapters are registered via registerAdapter() — one per channel.
 * - Domain services must NOT call NotificationService directly.
 *
 * Depends on:
 * - EventBus (event system) for receiving domain events
 * - NotificationAdapter implementations for delivery
 * - PreferencesService (optional) for per-channel preference checks
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  Notification,
  NotificationChannel,
  NotificationPayload,
  NotificationType,
} from '../models/notification.js';
import type { PreferencesService } from './preferences.service.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();
  private preferencesService: PreferencesService | null = null;

  constructor(private eventBus: EventBus) {
    this.registerEventHandlers();
  }

  /**
   * Set the preferences service for checking user notification preferences.
   * Optional — if not set, all notifications are sent (backwards compatible).
   */
  setPreferencesService(preferencesService: PreferencesService): void {
    this.preferencesService = preferencesService;
  }

  /**
   * Register a notification adapter for a delivery channel.
   * Only one adapter per channel is supported — registering a second
   * adapter for the same channel replaces the first.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registered adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Subscribe to domain events that should trigger notifications.
   * All event subscriptions go through EventBus.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created — send confirmation notification to all enabled channels.
   */
  private handleOrderCreated(event: OrderCreatedEvent): void {
    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    const basePayload = {
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      type: 'order_confirmation' as NotificationType,
      priority: 'normal' as const,
      metadata: { orderId: event.order.id, userId: event.user.id },
    };

    const channels = this.getChannelsForNotification(event.user.id, 'order_confirmation');

    if (channels.length === 0) {
      this.logger.info(`Skipping order confirmation for order ${event.order.id} — user preferences`);
      return;
    }

    this.logger.info(`Sending order confirmation for order ${event.order.id}`);

    for (const channel of channels) {
      this.sendNotification({
        ...basePayload,
        recipient: event.user.email,
        channel,
      });
    }
  }

  /**
   * Handle order status change — notify user of update on all enabled channels.
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    const basePayload = {
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      type: 'order_status_update' as NotificationType,
      priority: 'normal' as const,
      metadata: {
        orderId: event.order.id,
        previousStatus: event.previousStatus,
        newStatus: event.newStatus,
      },
    };

    const channels = this.getChannelsForNotification(event.order.userId, 'order_status_update');

    if (channels.length === 0) {
      this.logger.info(
        `Skipping status update for order ${event.order.id} — user preferences`,
      );
      return;
    }

    this.logger.info(
      `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    for (const channel of channels) {
      this.sendNotification({
        ...basePayload,
        recipient: event.order.userId,
        channel,
      });
    }
  }

  /**
   * Determine which channels should receive a notification for a given user.
   * If no PreferencesService is set, defaults to ['email'] for backward compatibility.
   */
  private getChannelsForNotification(
    userId: string,
    notificationType: NotificationType,
  ): NotificationChannel[] {
    if (!this.preferencesService) {
      return ['email'];
    }

    return this.preferencesService.getEnabledChannels(userId, notificationType);
  }

  /**
   * Send a notification through the appropriate adapter.
   * Records the notification regardless of whether an adapter is registered.
   */
  private sendNotification(payload: NotificationPayload): void {
    const notification: Notification = {
      id: generateNotificationId(),
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      type: payload.type,
      channel: payload.channel,
      priority: payload.priority,
      status: 'pending',
      metadata: payload.metadata,
      createdAt: new Date(),
    };

    const adapter = this.adapters.get(payload.channel);
    if (adapter) {
      adapter.send(payload).then((result) => {
        notification.status = result.success ? 'sent' : 'failed';
        notification.sentAt = new Date();

        this.eventBus.emit({
          type: 'notification:sent',
          notificationId: notification.id,
          channel: payload.channel,
          success: result.success,
          error: result.error,
          timestamp: new Date(),
        });
      });
    } else {
      this.logger.warn(`No adapter registered for channel: ${payload.channel}`);
      notification.status = 'sent';
      notification.sentAt = new Date();
    }

    this.notifications.push(notification);
    this.logger.info(`Notification ${notification.id} sent to ${payload.recipient}`);
  }

  /**
   * Get all notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

