import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { Database } from '../../src/utils/database.js';
import { UserPreferencesRepository } from '../../src/repositories/user-preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import type { UserCreatedEvent } from '../../src/events/event-types.js';

describe('PreferencesService', () => {
  let db: Database;
  let eventBus: EventBus;
  let repository: UserPreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();
    repository = new UserPreferencesRepository(db);
    service = new PreferencesService(repository, eventBus);
    resetPreferencesIdCounter();
  });

  describe('auto-create on user:created', () => {
    it('should create default preferences when a user is created', async () => {
      const event: UserCreatedEvent = {
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const prefs = service.getPreferences('user-1');
      expect(prefs).toBeDefined();
      expect(prefs!.userId).toBe('user-1');
      expect(prefs!.emailEnabled).toBe(true);
      expect(prefs!.emailFrequency).toBe('immediate');
      expect(prefs!.enabledCategories).toEqual([
        'order_confirmation',
        'order_status_update',
        'welcome',
        'account_updated',
      ]);
      // Verify per-channel defaults
      expect(prefs!.channels.email.enabled).toBe(true);
      expect(prefs!.channels.email.frequency).toBe('immediate');
      expect(prefs!.channels.sms.enabled).toBe(false);
      expect(prefs!.channels.webhook.enabled).toBe(false);
    });

    it('should not overwrite existing preferences on duplicate user:created event', async () => {
      service.createPreferences({
        userId: 'user-1',
        emailEnabled: false,
      });

      const event: UserCreatedEvent = {
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const prefs = service.getPreferences('user-1');
      expect(prefs!.emailEnabled).toBe(false);
    });
  });

  describe('createPreferences', () => {
    it('should create preferences with defaults when no options provided', () => {
      const prefs = service.createPreferences({ userId: 'user-1' });

      expect(prefs.id).toBe('pref-0001');
      expect(prefs.userId).toBe('user-1');
      expect(prefs.emailEnabled).toBe(true);
      expect(prefs.emailFrequency).toBe('immediate');
      expect(prefs.enabledCategories).toHaveLength(4);
      expect(prefs.channels.email.enabled).toBe(true);
      expect(prefs.channels.sms.enabled).toBe(false);
      expect(prefs.channels.webhook.enabled).toBe(false);
    });

    it('should create preferences with custom settings', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        emailEnabled: true,
        emailFrequency: 'daily_digest',
        enabledCategories: ['order_confirmation'],
      });

      expect(prefs.emailFrequency).toBe('daily_digest');
      expect(prefs.enabledCategories).toEqual(['order_confirmation']);
      expect(prefs.channels.email.frequency).toBe('daily_digest');
      expect(prefs.channels.email.categories).toEqual(['order_confirmation']);
    });

    it('should create preferences with per-channel settings', () => {
      const prefs = service.createPreferences({
        userId: 'user-1',
        channels: {
          email: { enabled: true, frequency: 'weekly_digest', categories: ['welcome'] },
          sms: { enabled: true, categories: ['order_confirmation', 'order_status_update'] },
          webhook: { enabled: true },
        },
      });

      expect(prefs.channels.email.enabled).toBe(true);
      expect(prefs.channels.email.frequency).toBe('weekly_digest');
      expect(prefs.channels.email.categories).toEqual(['welcome']);
      expect(prefs.channels.sms.enabled).toBe(true);
      expect(prefs.channels.sms.categories).toEqual(['order_confirmation', 'order_status_update']);
      expect(prefs.channels.webhook.enabled).toBe(true);
      // Legacy fields sync with email channel
      expect(prefs.emailEnabled).toBe(true);
      expect(prefs.emailFrequency).toBe('weekly_digest');
      expect(prefs.enabledCategories).toEqual(['welcome']);
    });

    it('should throw when preferences already exist for user', () => {
      service.createPreferences({ userId: 'user-1' });

      expect(() => service.createPreferences({ userId: 'user-1' })).toThrow(
        'Preferences already exist for user user-1',
      );
    });

    it('should generate sequential IDs', () => {
      const p1 = service.createPreferences({ userId: 'user-1' });
      const p2 = service.createPreferences({ userId: 'user-2' });

      expect(p1.id).toBe('pref-0001');
      expect(p2.id).toBe('pref-0002');
    });
  });

  describe('updatePreferences', () => {
    it('should update email enabled setting', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', { emailEnabled: false });

      expect(updated.emailEnabled).toBe(false);
      expect(updated.emailFrequency).toBe('immediate');
      expect(updated.channels.email.enabled).toBe(false);
    });

    it('should update email frequency', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        emailFrequency: 'weekly_digest',
      });

      expect(updated.emailFrequency).toBe('weekly_digest');
      expect(updated.channels.email.frequency).toBe('weekly_digest');
    });

    it('should update enabled categories', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        enabledCategories: ['order_confirmation', 'welcome'],
      });

      expect(updated.enabledCategories).toEqual(['order_confirmation', 'welcome']);
      expect(updated.channels.email.categories).toEqual(['order_confirmation', 'welcome']);
    });

    it('should update SMS channel preferences', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        channels: {
          sms: { enabled: true, categories: ['order_status_update'] },
        },
      });

      expect(updated.channels.sms.enabled).toBe(true);
      expect(updated.channels.sms.categories).toEqual(['order_status_update']);
      // Email should be unchanged
      expect(updated.channels.email.enabled).toBe(true);
    });

    it('should update webhook channel preferences', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        channels: {
          webhook: { enabled: true, categories: ['order_confirmation'] },
        },
      });

      expect(updated.channels.webhook.enabled).toBe(true);
      expect(updated.channels.webhook.categories).toEqual(['order_confirmation']);
    });

    it('should update multiple channels at once', () => {
      service.createPreferences({ userId: 'user-1' });

      const updated = service.updatePreferences('user-1', {
        channels: {
          email: { frequency: 'daily_digest' },
          sms: { enabled: true },
          webhook: { enabled: true },
        },
      });

      expect(updated.channels.email.frequency).toBe('daily_digest');
      expect(updated.channels.sms.enabled).toBe(true);
      expect(updated.channels.webhook.enabled).toBe(true);
    });

    it('should throw when no preferences exist', () => {
      expect(() =>
        service.updatePreferences('user-1', { emailEnabled: false }),
      ).toThrow('No preferences found for user user-1');
    });

    it('should update the updatedAt timestamp', () => {
      const prefs = service.createPreferences({ userId: 'user-1' });
      const originalUpdatedAt = prefs.updatedAt;

      const updated = service.updatePreferences('user-1', { emailEnabled: false });

      expect(updated.updatedAt.getTime()).toBeGreaterThanOrEqual(originalUpdatedAt.getTime());
    });
  });

  describe('shouldSendNotification', () => {
    it('should return true when no preferences exist (opt-out model)', () => {
      expect(service.shouldSendNotification('user-1', 'order_confirmation')).toBe(true);
    });

    it('should return true when email is enabled and category is subscribed', () => {
      service.createPreferences({ userId: 'user-1' });

      expect(service.shouldSendNotification('user-1', 'order_confirmation')).toBe(true);
    });

    it('should return false when email is globally disabled', () => {
      service.createPreferences({ userId: 'user-1', emailEnabled: false });

      expect(service.shouldSendNotification('user-1', 'order_confirmation')).toBe(false);
    });

    it('should return false when category is not in enabled list', () => {
      service.createPreferences({
        userId: 'user-1',
        enabledCategories: ['welcome'],
      });

      expect(service.shouldSendNotification('user-1', 'order_confirmation')).toBe(false);
    });

    it('should return true for subscribed category even when others are disabled', () => {
      service.createPreferences({
        userId: 'user-1',
        enabledCategories: ['order_confirmation'],
      });

      expect(service.shouldSendNotification('user-1', 'order_confirmation')).toBe(true);
      expect(service.shouldSendNotification('user-1', 'order_status_update')).toBe(false);
    });

    it('should check SMS channel preferences when channel is sms', () => {
      service.createPreferences({
        userId: 'user-1',
        channels: {
          sms: { enabled: true, categories: ['order_confirmation'] },
        },
      });

      expect(service.shouldSendNotification('user-1', 'order_confirmation', 'sms')).toBe(true);
      expect(service.shouldSendNotification('user-1', 'welcome', 'sms')).toBe(false);
    });

    it('should return false for SMS when SMS is disabled', () => {
      service.createPreferences({ userId: 'user-1' }); // SMS disabled by default

      expect(service.shouldSendNotification('user-1', 'order_confirmation', 'sms')).toBe(false);
    });

    it('should check webhook channel preferences', () => {
      service.createPreferences({
        userId: 'user-1',
        channels: {
          webhook: { enabled: true, categories: ['order_status_update'] },
        },
      });

      expect(service.shouldSendNotification('user-1', 'order_status_update', 'webhook')).toBe(true);
      expect(service.shouldSendNotification('user-1', 'order_confirmation', 'webhook')).toBe(false);
    });

    it('should allow in_app channel (no preference support)', () => {
      service.createPreferences({ userId: 'user-1', emailEnabled: false });

      // in_app has no preference gating, so it should always be allowed
      expect(service.shouldSendNotification('user-1', 'order_confirmation', 'in_app')).toBe(true);
    });

    it('should default to email channel when channel is omitted', () => {
      service.createPreferences({ userId: 'user-1', emailEnabled: false });

      // Without channel param, defaults to email — which is disabled
      expect(service.shouldSendNotification('user-1', 'order_confirmation')).toBe(false);
    });
  });

  describe('getEmailFrequency', () => {
    it('should return immediate when no preferences exist', () => {
      expect(service.getEmailFrequency('user-1')).toBe('immediate');
    });

    it('should return the configured frequency', () => {
      service.createPreferences({
        userId: 'user-1',
        emailFrequency: 'daily_digest',
      });

      expect(service.getEmailFrequency('user-1')).toBe('daily_digest');
    });
  });

  describe('getEnabledChannels', () => {
    it('should return only email for default preferences', () => {
      service.createPreferences({ userId: 'user-1' });

      const channels = service.getEnabledChannels('user-1', 'order_confirmation');
      expect(channels).toEqual(['email']);
    });

    it('should return email for unknown users', () => {
      const channels = service.getEnabledChannels('user-999', 'order_confirmation');
      expect(channels).toEqual(['email']);
    });

    it('should return multiple enabled channels', () => {
      service.createPreferences({
        userId: 'user-1',
        channels: {
          sms: { enabled: true },
          webhook: { enabled: true },
        },
      });

      const channels = service.getEnabledChannels('user-1', 'order_confirmation');
      expect(channels).toContain('email');
      expect(channels).toContain('sms');
      expect(channels).toContain('webhook');
      expect(channels).toHaveLength(3);
    });

    it('should filter by category per channel', () => {
      service.createPreferences({
        userId: 'user-1',
        channels: {
          email: { categories: ['order_confirmation'] },
          sms: { enabled: true, categories: ['order_status_update'] },
        },
      });

      const confirmChannels = service.getEnabledChannels('user-1', 'order_confirmation');
      expect(confirmChannels).toEqual(['email']);

      const statusChannels = service.getEnabledChannels('user-1', 'order_status_update');
      expect(statusChannels).toEqual(['sms']);
    });

    it('should return empty array when all channels disabled for category', () => {
      service.createPreferences({
        userId: 'user-1',
        emailEnabled: false,
      });

      const channels = service.getEnabledChannels('user-1', 'order_confirmation');
      expect(channels).toEqual([]);
    });
  });

  describe('getPreferences', () => {
    it('should return undefined for unknown user', () => {
      expect(service.getPreferences('user-999')).toBeUndefined();
    });

    it('should return preferences for known user', () => {
      service.createPreferences({ userId: 'user-1' });

      const prefs = service.getPreferences('user-1');
      expect(prefs).toBeDefined();
      expect(prefs!.userId).toBe('user-1');
    });
  });
});

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { Database } from '../../src/utils/database.js';
import { UserPreferencesRepository } from '../../src/repositories/user-preferences.repository.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import { SmsAdapter } from '../../src/adapters/sms.adapter.js';
import { WebhookAdapter } from '../../src/adapters/webhook.adapter.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('NotificationService', () => {
  let eventBus: EventBus;
  let service: NotificationService;
  let emailAdapter: EmailAdapter;

  beforeEach(() => {
    eventBus = new EventBus();
    service = new NotificationService(eventBus);
    emailAdapter = new EmailAdapter();
    service.registerAdapter(emailAdapter);
    resetNotificationIdCounter();
  });

  describe('order:created handler', () => {
    it('should send notification on order created', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          ],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.recipient).toBe('alice@example.com');
      expect(notifications[0]?.subject).toContain('Order Confirmation');
      expect(notifications[0]?.body).toContain('Widget x2');
      expect(notifications[0]?.body).toContain('$20.00');
    });

    it('should include all items in notification body', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
            { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
          ],
          total: 45,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications[0]?.body).toContain('Widget x2');
      expect(notifications[0]?.body).toContain('Gadget x1');
    });
  });

  describe('order:status-changed handler', () => {
    it('should send notification on status change via EventBus', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.subject).toContain('Order Update');
      expect(notifications[0]?.body).toContain('pending');
      expect(notifications[0]?.body).toContain('confirmed');
    });
  });

  describe('adapter registration', () => {
    it('should deliver notifications through registered adapter', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emails = emailAdapter.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('alice@example.com');
      expect(emails[0]?.subject).toContain('Order Confirmation');
    });
  });

  describe('multi-channel delivery', () => {
    let db: Database;
    let prefsRepository: UserPreferencesRepository;
    let prefsService: PreferencesService;
    let smsAdapter: SmsAdapter;
    let webhookAdapter: WebhookAdapter;

    beforeEach(() => {
      db = new Database();
      prefsRepository = new UserPreferencesRepository(db);
      prefsService = new PreferencesService(prefsRepository, eventBus);
      service.setPreferencesService(prefsService);
      resetPreferencesIdCounter();

      smsAdapter = new SmsAdapter();
      webhookAdapter = new WebhookAdapter({ url: 'https://hooks.example.com/notify' });
      service.registerAdapter(smsAdapter);
      service.registerAdapter(webhookAdapter);
    });

    it('should send to all enabled channels for a notification type', async () => {
      prefsService.createPreferences({
        userId: 'user-1',
        channels: {
          email: { enabled: true },
          sms: { enabled: true, categories: ['order_confirmation'] },
          webhook: { enabled: true, categories: ['order_confirmation'] },
        },
      });

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(3);
      const channels = notifications.map((n) => n.channel);
      expect(channels).toContain('email');
      expect(channels).toContain('sms');
      expect(channels).toContain('webhook');
    });

    it('should skip channels that are disabled', async () => {
      prefsService.createPreferences({
        userId: 'user-1',
        channels: {
          email: { enabled: true },
          sms: { enabled: false },
        },
      });

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.channel).toBe('email');
    });

    it('should skip all notifications when all channels disabled for category', async () => {
      prefsService.createPreferences({
        userId: 'user-1',
        emailEnabled: false,
      });

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(service.getNotifications()).toHaveLength(0);
    });

    it('should respect per-channel category filtering', async () => {
      prefsService.createPreferences({
        userId: 'user-1',
        channels: {
          email: { categories: ['order_confirmation'] },
          sms: { enabled: true, categories: ['order_status_update'] },
        },
      });

      // Order created -> order_confirmation: only email should receive
      const createEvent: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(createEvent);

      let notifications = service.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.channel).toBe('email');

      service.clearNotifications();

      // Status change -> order_status_update: only SMS should receive
      const statusEvent: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 10,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      await eventBus.emit(statusEvent);

      notifications = service.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.channel).toBe('sms');
    });

    it('should send to email by default when no preferences service is set', async () => {
      // Create a fresh service without preferences
      const freshService = new NotificationService(eventBus);
      freshService.registerAdapter(emailAdapter);
      freshService.registerAdapter(smsAdapter);

      // Need a separate eventBus to avoid duplicate handlers
      const freshBus = new EventBus();
      const freshServiceWithBus = new NotificationService(freshBus);
      freshServiceWithBus.registerAdapter(new EmailAdapter());
      freshServiceWithBus.registerAdapter(new SmsAdapter());

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-2',
          userId: 'user-2',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-2',
          name: 'Bob',
          email: 'bob@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await freshBus.emit(event);

      const notifications = freshServiceWithBus.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.channel).toBe('email');
    });
  });

  describe('notification management', () => {
    it('should count notifications', async () => {
      expect(service.getNotificationCount()).toBe(0);

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      expect(service.getNotificationCount()).toBe(1);
    });

    it('should filter by recipient', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(service.getNotificationsForRecipient('alice@example.com')).toHaveLength(1);
      expect(service.getNotificationsForRecipient('bob@example.com')).toHaveLength(0);
    });

    it('should clear notifications', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      service.clearNotifications();
      expect(service.getNotificationCount()).toBe(0);
    });

    it('should generate sequential notification IDs', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-2',
          userId: 'user-1',
          items: [],
          total: 30,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      });

      const notifications = service.getNotifications();
      expect(notifications[0]?.id).toBe('notif-0001');
      expect(notifications[1]?.id).toBe('notif-0002');
    });

    it('should set notification type and channel', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      const notification = service.getNotifications()[0];
      expect(notification?.type).toBe('order_status_update');
      expect(notification?.channel).toBe('email');
    });
  });
});

